public class DefaultMethod {
    interface Greeter {
        String greet(String name);
        default String greetLoud(String name) {
            return greet(name).toUpperCase();
        }
    }
    static class FormalGreeter implements Greeter {
        public String greet(String name) { return "Dear " + name; }
    }
    static class CasualGreeter implements Greeter {
        public String greet(String name) { return "hey " + name; }
        @Override public String greetLoud(String name) { return greet(name) + "!!!"; }
    }
    public static void main(String[] args) {
        Greeter f = new FormalGreeter();
        Greeter c = new CasualGreeter();
        System.out.println(f.greetLoud("Alice"));
        System.out.println(c.greetLoud("Bob"));
    }
}
